    const entities = this.entities;

    // Support dotted identifiers in contexts that accept "entity" values
    // (e.g. @layer foo.bar { ... }). In Less 4.4.0 a regression caused
    // `foo.baz` to be parsed as two entities (`foo` and `.baz`), leaving
    // unexpected input and ultimately triggering "at-rule options not recognised".
    const dottedKeyword = entities.dottedKeyword && entities.dottedKeyword();
    if (dottedKeyword) {
        return dottedKeyword;
    }

    return this.comment() || entities.literal() || entities.variable() || entities.url() ||
        entities.property() || entities.call() || entities.keyword() || this.mixin.call(true) ||
        entities.javascript();
},

