                quoted: function (forceEscaped) {
                    let str;
                    const index = parserInput.i;
                    let isEscaped = false;

                    parserInput.save();
                    if (parserInput.$char('~')) {
                        isEscaped = true;
                    } else if (forceEscaped) {
                        parserInput.restore();
                        return;
                    }

                    str = parserInput.$quoted();
                    if (!str) {
                        parserInput.restore();
                        return;
                    }
                    parserInput.forget();

                    return new(tree.Quoted)(str.charAt(0), str.substr(1, str.length - 2), isEscaped, index + currentIndex, fileInfo);
                },

                //
                // A catch-all word, such as:
                //
                //     black border-collapse
                //
                dottedKeyword: function() {
                    // CSS layer names support dot-separated identifiers: foo.bar.baz
                    // Parse as a single Keyword so at-rules like `@layer foo.bar {}`
                    // can pass through untouched.
                    parserInput.save();
                    const k = parserInput.$re(/^(?:[\w-]|\\(?:[A-Fa-f0-9]{1,6} ?|[^A-Fa-f0-9]))+(?:\.(?:[\w-]|\\(?:[A-Fa-f0-9]{1,6} ?|[^A-Fa-f0-9]))+)*/);
                    if (k && k.indexOf('.') !== -1) {
                        parserInput.forget();
                        return new(tree.Keyword)(k);
